import React, { useEffect, useRef } from "react";
import { useState } from "react"
import BlurredImage, { BlurredImageProps } from "./BlurredImage";
import { sleep } from "../utils";

interface AnimatedProps {
    animationIn?: string;
    animationOut?: string;
    intersectionOffset?: number;
    intersectionRatio?: number;
    className?: string;
    observableRef?: React.RefObject<HTMLDivElement | null>;
    initialClassName?: string;
    animationDelay?: number; // ms
}

interface AnimatedTextProps extends AnimatedProps {
    text?: string;
}

interface AnimatedElementProps extends AnimatedProps {
    children?: React.JSX.Element;
}

interface AnimatedImageProps extends BlurredImageProps, AnimatedProps { }

function isText(data: any): data is AnimatedTextProps {
    return 'text' in data;
}

function isElement(data: any): data is AnimatedElementProps {
    return 'children' in data;
}

function isImage(data: any): data is AnimatedImageProps {
    return 'imageSrc' in data;
}

function AnimatedComponent(props: AnimatedTextProps | AnimatedElementProps | AnimatedProps | AnimatedImageProps) {
    let ratio = -1;
    const defaultIntersectionOffset = 50;
    const defaultIntersectionRatio = 0.2;
    const initialClassName = props.initialClassName ?? "invisible";

    const defaultObservableRef = useRef<HTMLDivElement>(null);

    const [animClass, setAnimClass] = useState(initialClassName);
    const [showImage, setShowImage] = useState(false);

    useEffect(() => {
        document.fonts.ready.then(function () {
            handleScroll(); // initial setup
        });
        window.addEventListener('scroll', handleScroll);
        window.addEventListener('resize', handleScroll);
        return () => {
            window.removeEventListener('scroll', handleScroll);
            window.removeEventListener('resize', handleScroll);
        }
    }, []);

    const handleScroll = () => {
        let ref = props.observableRef ?? defaultObservableRef;
        if (ref.current) {
            const observedTop = ref.current.offsetTop;
            const observedBottom = observedTop + ref.current.offsetHeight;
            const top = window.scrollY + (props.intersectionOffset ?? defaultIntersectionOffset);
            const bottom = window.scrollY + window.innerHeight - (props.intersectionOffset ?? defaultIntersectionOffset);
            const ratioValue = Math.max(0,
                Math.min(bottom, observedBottom) - Math.max(top, observedTop)) / (observedBottom - observedTop);
            const newRatio = Math.round(ratioValue * 100) / 100;

            if (newRatio !== ratio) {
                if (isImage(props) &&
                    newRatio >= (props.intersectionRatio ?? defaultIntersectionRatio) &&
                    !showImage) {
                    setShowImage(true);
                }
                let newAnimClass = newRatio >= (props.intersectionRatio ?? defaultIntersectionRatio) ?
                    props.animationIn ?? " " :
                    ratio >= (props.intersectionRatio ?? defaultIntersectionRatio) ?
                        props.animationOut ?? " " :
                        initialClassName;
                if (newAnimClass !== animClass) {
                    updateAnimClass(newAnimClass);
                }
                ratio = newRatio;
            }
        }
    }

    const updateAnimClass = async (newClass: string) => {
        if (props.animationDelay) {
            await sleep(props.animationDelay);
        }
        setAnimClass(newClass);
    }

    if (isText(props)) {
        return (
            <div
                ref={props.observableRef ? undefined : defaultObservableRef}
                className={`${(props.className ?? "")} ${animClass}`}>
                {props.text}
            </div>
        );
    } else if (isElement(props)) {
        return (
            <div
                ref={props.observableRef ? undefined : defaultObservableRef}
                className={`${(props.className ?? "")} ${animClass}`}>
                {props.children}
            </div>
        );
    } else if (isImage(props)) {
        return (
            <div
                ref={props.observableRef ? undefined : defaultObservableRef}
                className={`${(props.className ?? "")} ${animClass}`}>
                <BlurredImage
                    show={showImage}
                    className={props.className}
                    duration={props.duration}
                    blurRadius={props.blurRadius}
                    delay={props.delay}
                    imageSrc={props.imageSrc} />
            </div>
        )
    } else {
        return (
            <div
                className={`${(props.className ?? "")} ${animClass}`}>
            </div>
        );
    }
}

export default AnimatedComponent;