import React from "react";

const radius = 433;
const dasharray = 2 * 3.14 * 433;

const ProgressIcon = (props: { total: number, current: number, color?: string }) => {
    const offset = dasharray - dasharray * (props.current / props.total);

    return (
        <svg width="964" height="964" viewBox="0 0 964 964" fill="none" xmlns="http://www.w3.org/2000/svg">
            <circle cx="482" cy="482" r={radius} transform="rotate(-90 482 482)" stroke={props.color ?? "#565656"} stroke-width="30" strokeDasharray={dasharray} strokeDashoffset={Math.min(Math.max(offset, 0), dasharray)} />
        </svg>
    );
}

export default ProgressIcon;