import React, { useEffect, useState } from 'react';
import './DmKs.css'

// constants
import STRINGS from './res/strings';
import { DRESS_COLORS, DrinkItem, DRINKS } from './Constants';

// components
import AnimatedComponent from '../app/components/AnimatedComponent';
import CalendarView from './components/CalendarView';
import YesHandwritten from './components/YesHandwritten';
import DresscodeIcon from './components/DresscodeIcon';
import TimingComponent, { TimingItem } from './components/TimingComponent';
import CheckboxIcon from '../app/components/Checkbox';
import TimerComponent from './components/TimerComponent';

// utils
import { sleep } from '../app/utils';

// images
import arrowdown from './res/images/arrow_down.svg';
import rings from './res/images/rings.svg';
import location from './res/images/location.svg';
import ceremony from './res/images/ceremony.svg';
import banquet from './res/images/banquet.svg';
import cake from './res/images/cake.svg';
import disco from './res/images/disco.svg';
import theend from './res/images/theend.svg';
import photo from './res/images/photo.png';
import map from './res/images/map.png';
import confirm from './res/images/confirm.svg';
import resend from './res/images/resend.svg';
import groom from './res/images/groom.svg';
import bride from './res/images/bride.svg';
import toaster from './res/images/toaster.svg';
import footer from './res/images/footer.svg';
import loading from './res/images/loading.svg';

function DmKs() {
  const weddingDate: Date = new Date(2025, 8, 23, 17);
  const groomName = "Дмитрий";
  const brideName = "Ксения";
  const groomNumber = "+7 910 879 05 39";
  const brideNumber = "+7 950 348 93 65";

  const [interactionEnabled, setInteractionEnabled] = useState(false);
  const [hideScrollIcon, setHideScrollIcon] = useState(false);
  const [selectedDrinks, setSelectedDrinks] = useState<DrinkItem[]>([]);
  const [confirmed, setConfirmed] = useState(false);
  const [answersSent, setAnswersSent] = useState(false);

  const [confirmLoading, setConfirmLoading] = useState(false);
  const [answersLoading, setAnswersLoading] = useState(false);

  const timings: TimingItem[] = [
    {
      time: STRINGS.TIMING_TIME_1,
      image: location,
      title: STRINGS.TIMING_TEXT_1,
      subtitle: STRINGS.TIMING_SUBTITLE_1
    },
    {
      time: STRINGS.TIMING_TIME_2,
      image: ceremony,
      title: STRINGS.TIMING_TEXT_2,
      subtitle: STRINGS.TIMING_SUBTITLE_2
    },
    {
      time: STRINGS.TIMING_TIME_3,
      image: banquet,
      title: STRINGS.TIMING_TEXT_3,
      subtitle: STRINGS.TIMING_SUBTITLE_3
    },
    {
      time: STRINGS.TIMING_TIME_4,
      image: cake,
      title: STRINGS.TIMING_TEXT_4,
      subtitle: STRINGS.TIMING_SUBTITLE_4
    },
    {
      time: STRINGS.TIMING_TIME_5,
      image: disco,
      title: STRINGS.TIMING_TEXT_5,
      subtitle: STRINGS.TIMING_SUBTITLE_5
    },
    {
      time: STRINGS.TIMING_TIME_6,
      image: theend,
      title: STRINGS.TIMING_TEXT_6,
      subtitle: STRINGS.TIMING_SUBTITLE_6
    }
  ]

  useEffect(() => {
    document.title = STRINGS.DOC_TITLE

    // window.scrollTo(0, 0);
    // document.body.style.overflow = 'hidden';
    document.fonts.ready.then(function () {
      setTimeout(() => {
        setInteractionEnabled(true);
        document.body.style.overflow = 'auto';
      }, 5000);
    });

    window.addEventListener('scroll', handleScroll);

    return () => {
      window.removeEventListener('scroll', handleScroll);
    }
  }, []);

  const handleScroll = () => {
    if (!hideScrollIcon) {
      let shouldHide = window.scrollY > 50;
      if (shouldHide) {
        window.removeEventListener('scroll', handleScroll);
        setHideScrollIcon(true);
      }
    }
  }

  const addSelectedDrink = (item: DrinkItem) => {
    let index = selectedDrinks.findIndex(i => i === item);
    if (index >= 0) {
      setSelectedDrinks(selectedDrinks.filter(i => i !== item));
    } else {
      setSelectedDrinks([...selectedDrinks, item]);
    }
  }

  const updateConfirmation = async (confirmed: boolean) => {
    setConfirmLoading(true);
    await sleep(1000); // imitate loading
    setConfirmed(confirmed);
    setConfirmLoading(false);
  }

  const updateAnswers = async () => {
    setAnswersLoading(true);
    await sleep(1000); // imitate loading
    setAnswersSent(true);
    setAnswersLoading(false);
  }

  const buildWelcomeContent = () => {
    return (
      <div className='welcome-content'>
        <div className='title-top-block'>
          <div className='title-block'>
            <div className='title-text opacity-in-linear' style={{ animationDelay: '500ms' }}>{STRINGS.SHE} {STRINGS.SAID}</div>
          </div>
          <div className='yes-text'>
            <YesHandwritten delay={1300} speedScale={1.4} />
          </div>
        </div>
        <div className='horizontal-divider scale-width-60' style={{ animationDelay: '2700ms' }} />
        <div className='invite-title opacity-in-linear' style={{ animationDelay: '3200ms' }}>{STRINGS.INVITE_TITLE}</div>
        <div className='names opacity-in-linear' style={{ animationDelay: '4000ms' }}>{STRINGS.NAME1 + " & " + STRINGS.NAME2}</div>
        <div
          className={`scroll-down-block ${interactionEnabled && !hideScrollIcon ? '' : 'hidden'}`}
          style={{
            animation:
              interactionEnabled ? 'opacity-in 500ms linear forwards, jumping 1200ms linear infinite' : ''
          }}>
          <div className='scroll-text'>{STRINGS.SCROLL_DOWN}</div>
          <img src={arrowdown} className="scroll-icon" alt="scroll" />
        </div>
      </div>
    );
  }

  const buildFirstInviteBlock = () => {
    return (
      <div className='base-block'>
        <AnimatedComponent
          className='base-title light mb0'
          text={STRINGS.WELCOME_TITLE}
          animationIn='slide-left-in'
          animationOut='slide-left-out' />
        <AnimatedComponent
          className='base-title mt0'
          text={STRINGS.GUESTS_TITLE}
          animationIn='slide-left-in'
          animationOut='slide-left-out' />

        <AnimatedComponent
          className='base-text'
          text={STRINGS.WELCOME_TEXT_FIRST}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
        <AnimatedComponent
          className='base-title light'
          text={STRINGS.WEDDING_DAY}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
        <AnimatedComponent
          className='base-text margin-bottom-large'
          text={STRINGS.WELCOME_TEXT_SECOND}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
        <AnimatedComponent
          className='base-text'
          text={STRINGS.WELCOME_TEXT_THIRD}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
      </div>
    );
  }

  const buildWhenBlock = () => {
    return (
      <div className='base-block'>
        <AnimatedComponent
          className='base-title'
          text={STRINGS.WHEN_TITLE}
          animationIn='slide-left-in'
          animationOut='slide-left-out' />
        <CalendarView year={weddingDate.getFullYear()} month={weddingDate.getMonth()} day={weddingDate.getDate()} />
      </div>
    );
  }

  const buildWhereBlock = () => {
    return (
      <div className='base-block'>
        <AnimatedComponent
          className='base-title'
          text={STRINGS.WHERE_TITLE}
          animationIn='slide-left-in'
          animationOut='slide-left-out' />
        <AnimatedComponent
          className='base-title light mb0 mt0'
          text={STRINGS.WHERE_TEXT}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
        <AnimatedComponent
          className='base-text small mb0'
          text={STRINGS.WHERE_ADDRESS}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
        <AnimatedComponent
          className='base-text xxsmall mt0'
          text={STRINGS.WHERE_ENTER}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />

        <img className="map-image" src={map} alt='map' />
        <AnimatedComponent
          className='base-text link bold mt0'
          animationIn='slide-right-in'
          animationOut='slide-right-out'>
          <text
            onClick={() => window.open(STRINGS.CORDS_URL, '_blank', 'noopener,noreferrer')}>
            {STRINGS.WHERE_SHOW}
          </text>
        </AnimatedComponent>
      </div>
    );
  }

  const buildDresscodeBlock = () => {
    return (
      <div className='base-block'>
        <AnimatedComponent
          className='base-title'
          text={STRINGS.DRESSCODE_TITLE}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
        <AnimatedComponent
          className='base-text small mt0'
          text={STRINGS.DRESSCODE_TEXT}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
        <div className='dress-colors-container' style={{ display: 'flex', flexDirection: 'row' }}>
          {DRESS_COLORS.map((color, i) => {
            return (
              <AnimatedComponent
                animationDelay={i * 100}
                animationIn='jumping-up-down'
                animationOut='opacity-out'>
                <DresscodeIcon fillColor={color} />
              </AnimatedComponent>);
          })}
        </div>
      </div>
    );
  }

  const buildTimingBlock = () => {
    return (
      <div className='base-block'>
        <AnimatedComponent
          className='base-title'
          text={STRINGS.TIMING_TITLE}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
        <div className="timing-container">
          {timings.map((t) => {
            return (
              <TimingComponent timing={t} />
            )
          })}
        </div>
      </div>
    );
  }

  const buildWishesBlock = () => {
    return (
      <div className='base-block'>
        <AnimatedComponent
          className='base-title'
          text={STRINGS.WISHES_TITLE}
          animationIn='slide-left-in'
          animationOut='slide-left-out' />
        <AnimatedComponent
          className='base-text mt0'
          text={STRINGS.WISHES_TEXT1}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
      </div>
    );
  }

  const buildQuestionnareBlock = () => {
    return (
      <div className='base-block'>
        <AnimatedComponent
          className='base-title'
          text={STRINGS.QUESTIONNAIRE_TITLE}
          animationIn='slide-left-in'
          animationOut='slide-left-out' />
        <AnimatedComponent
          className='base-text mt0 mb0 small'
          text={STRINGS.QUESTIONNAIRE_TEXT}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
        <div className='base-block'>
          <AnimatedComponent
            className='base-text large mt24 bold'
            text={STRINGS.QUESTIONNAIRE_CONFIRMATION_TEXT}
            animationIn='slide-right-in'
            animationOut='slide-right-out' />
          <AnimatedComponent
            className='base-text mt0 xxsmall'
            text={STRINGS.QUESTIONNAIRE_CONFIRMATION_TEXT_HINT}
            animationIn='slide-right-in'
            animationOut='slide-right-out' />
          <div className={`confirm-button ${confirmLoading ? "loading" : confirmed ? "confirmed bold" : ""}`}
            aria-disabled={confirmLoading}
            onClick={() => { if (!confirmed) { updateConfirmation(true) } }}>
            <img className='confirm-icon' width={20} src={confirmLoading ? loading : confirm} />
            <div className='base-text'>{STRINGS.QUESTIONNAIRE_CONFIRMATION_WEDO}</div>
          </div>
          <div className={`base-text decline-button clickable bold ${confirmed ? "" : "hidden"}`}
            aria-disabled={confirmLoading}
            onClick={() => updateConfirmation(false)}>
            {confirmed ? STRINGS.QUESTIONNAIRE_CONFIRMATION_DECLINE : "."}
          </div>
        </div>
        <div className='base-block'>
          <AnimatedComponent
            className='base-text large mt24 bold'
            text={STRINGS.QUESTIONNAIRE_DRINKS_TEXT}
            animationIn='slide-right-in'
            animationOut='slide-right-out' />
          <AnimatedComponent
            className='base-text mt0 small'
            text={STRINGS.QUESTIONNAIRE_DRINKS_TEXT_HINT}
            animationIn='slide-right-in'
            animationOut='slide-right-out' />
          <div className='base-block left-aligned w95'>
            {DRINKS.map((d) => {
              return (<div className="checkbox-item" onClick={() => addSelectedDrink(d)}>
                <CheckboxIcon fillColor='#343434' checked={selectedDrinks.indexOf(d) >= 0} />
                <div className="base-text m0 small">{d.name}</div>
              </div>)
            })}
          </div>
        </div>
        <div className='base-block'>
          <AnimatedComponent
            className='base-text mt24 bold'
            text={STRINGS.QUESTIONNAIRE_MUSIC_TEXT}
            animationIn='slide-right-in'
            animationOut='slide-right-out' />
          <AnimatedComponent
            className='base-text mt0 small'
            text={STRINGS.QUESTIONNAIRE_MUSIC_TEXT_HINT}
            animationIn='slide-right-in'
            animationOut='slide-right-out' />
          <textarea
            className='base-text mt0 left-aligned w95 textfield-item'
            placeholder={STRINGS.QUESTIONNAIRE_MUSIC_PLACEHOLDER} />
        </div>
        <div className='base-block'>
          <AnimatedComponent
            className='base-text mt24 bold'
            text={STRINGS.QUESTIONNAIRE_ADDITIONS_TEXT}
            animationIn='slide-right-in'
            animationOut='slide-right-out' />
          <AnimatedComponent
            className='base-text mt0 small'
            text={STRINGS.QUESTIONNAIRE_ADDITIONS_TEXT_HINT}
            animationIn='slide-right-in'
            animationOut='slide-right-out' />
          <textarea
            className='base-text mt0 left-aligned w95 textfield-item'
            placeholder={STRINGS.QUESTIONNAIRE_ADDITIONS_PLACEHOLDER} />
        </div>
        <div className='base-block'>
          <div className={`base-text decline-button bold ${answersSent && !answersLoading ? "" : "hidden"}`}>
            {answersSent ? STRINGS.QUESTIONNAIRE_SENT : "."}
          </div>
          <div className={`confirm-button ${answersLoading ? "loading" : answersSent ? "confirmed" : ""}`}
            onClick={() => updateAnswers()}>
            <img className='confirm-icon' width={20} src={answersLoading ? loading : resend} />
            <div className='base-text'>{answersSent ? STRINGS.QUESTIONNAIRE_SEND_AGAIN : STRINGS.QUESTIONNAIRE_SEND}</div>
          </div>
          <div className={`base-text xxsmall decline-button ${answersSent && !answersLoading ? "" : "hidden"}`}>
            {answersSent ? STRINGS.QUESTIONNAIRE_SENT_HINT : "."}
          </div>
        </div>
      </div>
    );
  }

  const buildContactsBlock = () => {
    return (
      <div className='base-block'>
        <AnimatedComponent
          className='base-title'
          text={STRINGS.CONTACTS_TITLE}
          animationIn='slide-left-in'
          animationOut='slide-left-out' />
        <div className='div-row'>
          <div className='contact-block'>
            <img src={groom} alt="groom" />
            <div className='div-col'>
              <div className='base-text bold'>
                {groomName}
              </div>
              <div className='base-text xsmall bold phone'>
                {groomNumber}
              </div>
            </div>
          </div>
          <div className='contact-block'>
            <img src={bride} alt="bride" />
            <div className='div-col'>
              <div className='base-text bold'>
                {brideName}
              </div>
              <div className='base-text xsmall bold phone'>
                {brideNumber}
              </div>
            </div>
          </div>
        </div>
        <div className='horizontal-divider' />
        <AnimatedComponent
          className='base-text xsmall mt0'
          text={STRINGS.CONTACTS_TOASTER_TEXT}
          animationIn='slide-right-in'
          animationOut='slide-right-out' />
        <div className='contact-block center'>
          <img src={toaster} alt="toaster" />
          <div className='div-col'>
            <div className='base-text bold'>
              Ведущий
            </div>
            <div className='base-text xsmall bold phone'>
              +7 987 012 34 56
            </div>
          </div>
        </div>
      </div>
    );
  }

  const buildFooterBlock = () => {
    return (
      <div className='base-block footer-block'>
        <div className='base-title mb0'>{STRINGS.SEE_U_SOON}</div>
        <div className='base-text'>{STRINGS.WITH_LOVE}</div>
        <div className='base-title mt0'>{groomName} и {brideName}</div>
        <img src={footer} alt="footer" />
      </div>
    );
  }

  return (
    <div className='content'>

      {buildWelcomeContent()}

      <div className='photo-content'>
        <AnimatedComponent
          className="photo"
          animationIn='opacity-in'
          animationOut='opacity-out'
          imageSrc={photo} />
      </div>

      {buildFirstInviteBlock()}

      <AnimatedComponent
        animationIn='opacity-in scale-in'
        animationOut='opacity-out scale-out'
        intersectionOffset={100}>
        <img src={rings} className="rings-logo" alt="rings" />
      </AnimatedComponent>

      {buildWhenBlock()}

      {buildWhereBlock()}

      {buildDresscodeBlock()}

      {buildTimingBlock()}

      {buildWishesBlock()}

      {buildQuestionnareBlock()}

      <TimerComponent date={weddingDate} />

      {buildContactsBlock()}

      {buildFooterBlock()}

    </div>
  );
}

export default DmKs;
