import React, { useRef } from "react"
import COMMON_STRINGS from '../../app/res/strings'
import AnimatedComponent from "../../app/components/AnimatedComponent";
import './CalendarView.css'
import selectedIcon from '../res/images/selecteddate.svg';

function CalendarView(props: { year: number, month: number, day: number }) {
    const observableRef = useRef<HTMLDivElement>(null);

    const weddingDate = new Date(props.year, props.month - 1, props.day);
    const dateTitle = weddingDate.toLocaleString('ru-RU', { month: 'long', year: "numeric" }).slice(0, -3);
    const startDate = new Date(props.year, props.month - 1, 1);

    const firstDayIndex = (startDate.getDay() === 0 ? 7 : startDate.getDay()) - 1;
    const daysInMonth = new Date(weddingDate.getFullYear(),
        weddingDate.getMonth() + 1,
        0).getDate();
    const days = [];
    for (let i = 0; i < firstDayIndex; i++) {
        days.push("");
    }
    for (let i = 1; i <= daysInMonth; i++) {
        days.push(`${i}`);
    }
    const weeksCount = Math.ceil(days.length / 7);
    const totalDays = weeksCount * 7;
    const daysDiff = totalDays - days.length;
    for (let i = 0; i < daysDiff; i++) {
        days.push("");
    }
    const weeks: string[][] = [[]];
    let currentWeek = 0;
    for (let i = 0; i < weeksCount; i++) {
        let s = days.slice(currentWeek * 7, currentWeek * 7 + 7);
        weeks.push(s);
        currentWeek++;
    }

    return (
        <div className='calendar-content' ref={observableRef}>
            <AnimatedComponent className='calendar-title'
                animationIn='slide-bottom-in'
                animationOut='slide-bottom-out'
                text={dateTitle} />
            <AnimatedComponent
                animationIn='slide-bottom-in'
                animationOut='slide-bottom-out'>
                <div className="calendar-row days">
                    {COMMON_STRINGS.DAYS_OF_WEEK.map((day) => {
                        return (
                            <div className="calendar-item">{day}</div>
                        );
                    })}
                </div>
            </AnimatedComponent>
            {weeks.map((w) => {
                return (
                    <AnimatedComponent
                        animationIn='slide-bottom-in'
                        animationOut='slide-bottom-out'>
                        <div className="calendar-row">
                            {w.map((d, i) => {
                                if (d === `${props.day}`) {
                                    return (
                                        <AnimatedComponent
                                            animationIn="calendar-selection"
                                            intersectionOffset={0}
                                            intersectionRatio={1}
                                            observableRef={observableRef}
                                            initialClassName="">
                                            <div className="calendar-item selected">
                                                <img className="selected-icon" src={selectedIcon} alt='selectedIcon' />
                                                <text>{d}</text>
                                            </div>
                                        </AnimatedComponent>
                                    )
                                } else {
                                    return (<div className={`calendar-item ${i > 4 ? 'bold' : ''}`}>{d}</div>)
                                }
                            })}
                        </div>
                    </AnimatedComponent>
                )
            })
            }
        </div>
    );
}

export default CalendarView