import React, { useState } from "react";

export interface BlurredImageProps {
    show?: boolean;
    className?: string;
    imageSrc: string;
    blurRadius?: number;
    duration?: number;
    delay?: number;
}

const BlurredImage = (props: BlurredImageProps) => {
    const defaultBlurRadius = 20;
    const defaultDuration = 500;
    const defaultDelay = 0;
    const [loaded, setLoaded] = useState(false);

    React.useEffect(() => {
        const img = new Image();
        img.src = props.imageSrc;
        document.fonts.ready.then(function () {
            setLoaded(true);
        });
    }, []);
    
    return (
        <img
            className={props.className}
            src={props.imageSrc}
            style={{
                filter: loaded && props.show ? "none" : `blur(${props.blurRadius ?? defaultBlurRadius}px)`,
                transition: loaded && props.show ? `filter ${props.duration ?? defaultDuration}ms ease` : "none",
                transitionDelay: loaded && props.show ? `${props.delay ?? defaultDelay}ms` : '',
                // animation: loaded && props.show ? `opacity-in ${props.duration ?? defaultDuration}ms linear` : '',
                // animationDelay: loaded && props.show ? `${props.delay ?? defaultDelay}ms` : ''
            }}
        />
    );
};

export default BlurredImage;